INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (22, 125727, 3, 73, '[转贴]RAP 说唱乐', '说唱乐的起源可以追溯到黑人音乐根源中吟咏的段落中，到了70年代说唱乐正式确立了自己的风格，其中最主要的功劳要归根于当时流行的迪斯科舞厅中的DJ们，他们将黑人当时正在风行的FUNK节奏混入流行的迪斯科节奏中，并且在唱片机上反复重复同一张的唱片的内容，做自己的LOOPS，随着那些在现在广为人知和DJ们普遍应用的“打碟”法出现，说唱开始被街头黑人文化所流传，并且衍生出相当丰富的分支，诸如西海岸说唱乐(West Coast Rap)、南部说唱乐(Southern Rap)、流行说唱乐(Pop Rap)、老派说唱乐(Old Schold)、中西部说唱乐(Midwest Rap)、拉丁说唱(Latin Rap)、硬核说唱(Hardcore Rap)、黑帮说唱(Gangsta Rap)、外来说唱乐(Foreign Rap)、东海岸说唱乐(East Coast Rap)、过渡说唱乐(Crossover Rap)、喜剧说唱乐(Comedy Rap)、基督教说唱(Christian Rap)、另类说唱乐(Alternative Rap)等等，我们现在所谓的HIP-HOP正是由这些流派综合了当今流行元素而诞生的新词汇。尽管早在90年代初期就有人认为这种絮絮叨叨，满是脏话粗口，叛逆词语的音乐会很快消失，而事实上，在90年代末，随着一批新进的说唱乐手和以白人为主的说唱摇滚的风行，曾经被黑人抛弃的音乐又重新回到了流行音乐的前端，至少在新世纪的现在，这个风潮还不会消退。 
<br>
<br>　　RAP是美国黑人音乐中的重要组成部分，是街头文化的主要基调，是世界流行音乐中的一块“黑色巧克力”。本文试图通过介绍几支美国当红RAP歌手/团体，让歌迷了解这些人的背景资料，找到自己喜欢的RAP明星。 
<br>
<br>　　首先，先简单的介绍一下关于Rap说唱乐的起源和发展过程.
<br>  
<br>　　70年代中期在黑人和纽约市外行政区的西班牙籍青年中间开始流行迪斯科、霹雳舞、涂鸦艺术和说唱乐。街区那些去不起时髦俱乐部的青少年厌倦了迪斯科音乐，他们演奏更重一些的黑人疯克流行音乐，来回重复同一张唱片的内容[比如詹姆斯&#183;布朗（BROWN，JAMES)的《跳起优美的舞步》（Get on the Good Foot)]，以制作他们自己的混音音乐，鼓励跳舞的人跳更有创造性的动作，很快这种舞被叫做露雳舞。 
<br>
<br>　　当主持人在音乐中加入说唱(开始时是用60年代流行的语言朗诵一些街头即兴诗歌)，这种音乐开始成为了说唱乐。在此之后，“大巫师特奥多”(Grand Wizard Theoder)更有所创新，他发明了“刮擦法”，即用手转动唱片，使唱针来回移动，以得到一种反复的、节奏鲜明的音乐效果。另一位DJ“大师”弗莱什(Grandmaster Flash)则使用一种节拍器，与经过剪接的唱片片段结合起来听。随之出现了一种街头亚文化，其成员(人称“节拍孩子”)身着统一制服，把音响接到路灯线路上获得免费供电，基于别人的作品或自己的想像力创造音乐。类似的音乐形式称做嬉蹦乐(Hip Hop)，洛夫巴格&#183;斯塔斯凯(Lovebug Starsky)用了“To the hiP，hop，hippedy hop”的歌词。由来自布隆克斯的乐队“糖山帮”(Sugar Hill Gang)在Sugar Hill公司1979年推出的《说唱乐手的乐趣》(Rapper''s Delight)成为一首风格奇特的上榜歌曲。这种新的黑人地下音乐将快速说出的流行词句与旋律相结合，带有强烈的节奏感，它的根源可追溯到无线电流行音乐广播，在这些节日中，DJ起着举足轻重的作用，正是他们通过无线电波使城市节奏与布鲁斯音乐风靡一时。他们在介绍唱片或歌曲时，往往使用一些押韵的俚语，妙语连珠且速度极快。这种语言风格是非洲黑人炫耀、赞美的颂歌，通过美国黑人的传统口语经常演唱的疯狂急速滑稽歌曲的风格。1980年Mercury公司发行的《霹雳》(The Breaks)也是一首新奇的歌曲，还有一些其他的新音乐。1982年阿弗里卡&#183;班巴塔(BAMBAATAA，AFRIKA)和他的“灵魂的声音力量”(Soul Sonic Force)乐队成功地进行了说唱乐历史上最具胆魄的一场革命，将“发电站”(KRAFTWERK)乐队的一首《泛欧特快》(Trans Europe Express)转换成一首叫《行星摇滚》(Planet Rock)的说唱乐。通过制作人阿瑟&#183;贝克(Arthur Baker)及说唱乐队“灵魂的声音力量”(Soul Sonic Force)的合作，班巴塔录制了一张唱片，融俱乐部风格、激烈的电子乐节奏、欧洲音乐和一种称为“DJ流行音乐”的新说唱乐形成为一体。 
<br>
<br>　　弗莱什(Flash，原名Joseph Saddler)是第一批剪辑唱片的大师，他的歌曲中加入了声音效果和节奏处理(摩擦唱片)。1982年，“疯狂五人”(The Furious Five)推出专辑《信息》(The Message)。后来主唱手梅勒&#183;梅尔(Melle Mel)离队，弗莱什出版了《源泉》(The Source)，更接近了街区的风格。主持人奇斯(Cheese)也是一名运用转盘和嘴皮子的奇才。 
<br>
<br>　　RUN―D．M．C．*是来自纽约市皇后区的3人组合(都生于1965年)，他们1986年的第3张专辑《上升的地狱》(Raosomg Hell)成为第1张说唱白金唱片，乔&#183;西蒙斯(Joe Simmons)、达里尔&#183;麦克(Darryl Mac)负责用鼓机、麦克风，贾森&#183;米泽尔(Jason Mizell)负责摩擦唱片，1986年在麦迪逊广场花园进行了演出，歌词充满了社会观点。有一些听众想寻求暴力，但西蒙斯说：“我们的歌迷知道我们不想这样做。”曾有人预言这种音乐形式会很快消亡，但却没有。贫民区的人民创造了他们自己的沟通方式，这种方式广为流传。1987年伦敦的波塞到纽约市录制了12寸单曲《伦敦波塞》，磁带A面用了伦敦的黑人方言口音，B面用了雷吉乐的风格，但说唱乐与其说是音乐，不如说是一种社会现象。具有讽刺意味的是它已用到了广告业中。在音乐上它相当于土豆片，但却不是通常的面包糊，不喜欢的人会关掉电视。“野孩”(BEASTIE BOYS)是来自中产阶级家庭的白人3人组合(其中一人于1987年因被控伤害一名女歌迷而在利物浦被捕，后无罪释放)，他们1987年的专辑《患病许可》(Licensed toⅢ)卖出了400万张，而购买者是一群一无所知的13岁的少年。这再一次证实了这样一个问题：“你说说唱乐是为了一个远大的目标还是仅仅为了哗众取宠？”', '说唱乐的起源可以追溯到黑人音乐根源中吟咏的段落中，到了70年代说唱乐正式确立了自己的风格，其中最主要的功劳要归根于当时流行的迪斯科舞厅中的DJ们，他们将黑人当时正在风行的FUNK节奏混入流行的迪斯科节奏中，并且在唱片机上反复重复同一张的唱片的内容，做自己的LOOPS，随着那些在现在广为人知和DJ们普遍应用的“打碟”法出现，说唱开始被街头黑人文化所流传，并且衍生出相当丰富的分支，诸如西海岸说唱乐(West Coast Rap)、南部说唱乐(Southern Rap)、流行说唱乐(Pop Rap)、老派说唱乐(Old Schold)、中西部说唱乐(Midwest Rap)、拉丁说唱(Latin Rap)、硬核说唱(Hardcore Rap)、黑帮说唱(Gangsta Rap)、外来说唱乐(Foreign Rap)、东海岸说唱乐(East Coast Rap)、过渡说唱乐(Crossover Rap)、喜剧说唱乐(Comedy Rap)、基督教说唱(Christian Rap)、另类说唱乐(Alternative Rap)等等，我们现在所谓的HIP-HOP正是由这些流派综合了当今流行元素而诞生的新词汇。尽管早在90年代初期就有人认为这种絮絮叨叨，满是脏话粗口，叛逆词语的音乐会很快消失，而事实上，在90年代末，随着一批新进的说唱乐手和以白人为主的说唱摇滚的风行，曾经被黑人抛弃的音乐又重新回到了流行音乐的前端，至少在新世纪的现在，这个风潮还不会消退。

